import type {IColumn, IFilters} from "@lmb-it/kitsconcerto-types";
import {type ColumnFilterMatchModeOptions} from "primereact/column";
import {FilterMatchMode} from "primereact/api";

export const showFilterMenu = (filter: IFilters | undefined): boolean => {
  if (!filter) {
    return false;
  }
  let showFilterMenu: boolean;
  switch (filter?.type) {
    case "multiSelect":
    case "buttons":
    case "tristate":
      showFilterMenu = false;

      break;
    default:
      showFilterMenu = true;
      break;
  }
  return showFilterMenu;
};

export const matchModesOptions = (
  filter: IFilters | undefined,
  t?: (key: string) => string,
): ColumnFilterMatchModeOptions[] | undefined => {
  const tr = (key: string, fallback: string) => t ? t(key) : fallback;

  const string: ColumnFilterMatchModeOptions[] = [
    { label: tr("contains", "Contains"), value: FilterMatchMode.CONTAINS },
    { label: tr("notContains", "Not contains"), value: FilterMatchMode.NOT_CONTAINS },
  ];
  const options: ColumnFilterMatchModeOptions[] = [
    { label: tr("equals", "Equals"), value: FilterMatchMode.EQUALS },
    { label: tr("notEquals", "Not equals"), value: FilterMatchMode.NOT_EQUALS },
  ];

  const number = [
    { label: tr("greaterThan", "Greater than"), value: FilterMatchMode.GREATER_THAN },
    {
      label: tr("greaterThanOrEqualTo", "Greater than or equal to"),
      value: FilterMatchMode.GREATER_THAN_OR_EQUAL_TO,
    },
    { label: tr("equals", "Equals"), value: FilterMatchMode.EQUALS },
    { label: tr("notEquals", "Not equals"), value: FilterMatchMode.NOT_EQUALS },
    { label: tr("lessThan", "Less than"), value: FilterMatchMode.LESS_THAN },
    {
      label: tr("lessThanOrEqualTo", "Less than or equal to"),
      value: FilterMatchMode.LESS_THAN_OR_EQUAL_TO,
    },
    { label: tr("between", "Between"), value: FilterMatchMode.BETWEEN },
  ];

  const multi = [{ label: tr("include", "Include"), value: FilterMatchMode.IN }];

  const date = [
    { label: tr("equal", "Equal"), value: FilterMatchMode.DATE_IS },
    { label: tr("after", "After"), value: FilterMatchMode.DATE_AFTER },
    { label: tr("before", "Before"), value: FilterMatchMode.DATE_BEFORE },
    { label: tr("not", "Not"), value: FilterMatchMode.DATE_IS_NOT },
    { label: tr("between", "Between"), value: FilterMatchMode.BETWEEN },
  ];

  switch (filter?.type) {
    case "multiSelect":
      return multi;

    case "buttons":
      if (filter.isMultiple) {
        return multi;
      } else {
        return string;
      }
    case "range":
    case "number":
      return number;
    case "date":
      return date;
    case "dropdown":
      return options;
    case "tristate":
      return undefined;
    default:
      return options;
  }
};

export const getPrimeDataType = (filter: IColumn<any>["filter"]) => {
  switch (filter?.type) {
    case "number":
    case "phone":
      return "numeric";
    case "dropdown":
    case "buttons":
    case "tristate":
    case "text":
      return "text";
    case "date":
      return "date";
    case "multiSelect":
    case "range":
      return undefined;
  }
};
